/// Qwen3-ASR end-to-end parity check against Python moona3k reference.
///
/// Reads reference data from benchmark/qwen3_asr/ref_data/ (generated by
/// python_ref.py) and compares Dart intermediate outputs at each stage:
///   1. Mel spectrogram
///   2. Audio encoder output
///   3. Prompt token construction
///   4. Prefill logits (top-k comparison)
///   5. Full transcription text
///
/// Usage (from the dart-mlx-ffi package root):
///   dart run benchmark/qwen3_asr/dart_parity.dart
import 'dart:convert';
import 'dart:io';
import 'dart:math' as math;
import 'dart:typed_data';

import 'package:dart_mlx_ffi/dart_mlx_ffi.dart';
import 'package:dart_mlx_ffi/models.dart';
import 'package:dart_mlx_ffi/src/models/qwen3_asr/audio_enc.dart';
import 'package:dart_mlx_ffi/src/models/qwen3_asr/config.dart';
import 'package:dart_mlx_ffi/src/models/qwen3_asr/generate.dart';
import 'package:dart_mlx_ffi/src/models/qwen3_asr/mel.dart';
import 'package:dart_mlx_ffi/src/models/qwen3_asr/mrope.dart';
import 'package:dart_mlx_ffi/src/models/qwen3_asr/text_dec.dart';

void main(List<String> args) {
  final refDir = '${Directory.current.path}/benchmark/qwen3_asr/ref_data';
  if (!Directory(refDir).existsSync()) {
    stderr.writeln('Reference data not found at $refDir');
    stderr.writeln('Run python_ref.py first to generate reference data.');
    exitCode = 1;
    return;
  }

  final home = Platform.environment['HOME'] ?? '';
  final modelPath =
      Platform.environment['CMDSPACE_QWEN3_ASR_MODEL']?.trim() ??
      '$home/.cmdspace/models/qwen3-asr/default';
  if (!Directory(modelPath).existsSync()) {
    stderr.writeln('Model not found at $modelPath');
    exitCode = 1;
    return;
  }

  stderr.writeln('Loading reference data from $refDir');
  stderr.writeln('Loading model from $modelPath');

  // Load reference metadata.
  final metadata =
      jsonDecode(File('$refDir/metadata.json').readAsStringSync())
          as Map<String, Object?>;
  stderr.writeln('Reference: ${metadata['audio_duration_s']}s audio');

  // Load test audio.
  final audioBytes = File('$refDir/test_audio.bin').readAsBytesSync();
  final audio = Float32List.sublistView(ByteData.sublistView(audioBytes));
  stderr.writeln(
    'Audio: ${audio.length} samples '
    '(${audio.length / 16000}s)',
  );

  // Load reference mel.
  final melShapeJson =
      jsonDecode(File('$refDir/mel_shape.json').readAsStringSync()) as List;
  final refMelShape = melShapeJson.cast<int>();
  final refMelBytes = File('$refDir/mel.bin').readAsBytesSync();
  final refMel = Float32List.sublistView(ByteData.sublistView(refMelBytes));

  // Load reference encoder output.
  final encShapeJson =
      jsonDecode(File('$refDir/encoder_shape.json').readAsStringSync()) as List;
  final refEncShape = encShapeJson.cast<int>();
  final refEncBytes = File('$refDir/encoder.bin').readAsBytesSync();
  final refEnc = Float32List.sublistView(ByteData.sublistView(refEncBytes));

  // Load reference text.
  final refText = File('$refDir/text.txt').readAsStringSync().trim();
  stderr.writeln('Reference text: "$refText"');

  // Load reference prompt tokens.
  Map<String, Object?>? refPromptData;
  final promptFile = File('$refDir/prompt_tokens.json');
  if (promptFile.existsSync()) {
    refPromptData =
        jsonDecode(promptFile.readAsStringSync()) as Map<String, Object?>;
  }

  // Load reference prefill logits.
  Map<String, Object?>? refLogitsData;
  final logitsFile = File('$refDir/prefill_logits.json');
  if (logitsFile.existsSync()) {
    refLogitsData =
        jsonDecode(logitsFile.readAsStringSync()) as Map<String, Object?>;
  }

  // Load reference gen tokens.
  Map<String, Object?>? refGenData;
  final genFile = File('$refDir/gen_tokens.json');
  if (genFile.existsSync()) {
    refGenData = jsonDecode(genFile.readAsStringSync()) as Map<String, Object?>;
  }

  // ─── Load model ───
  final config = Qwen3AsrConfig.fromSnapshot(modelPath);
  final tensors = _loadTensors(modelPath);
  final runner = Qwen3AsrRunner.load(modelPath);

  // ─── Stage 1: Mel spectrogram ───
  stderr.writeln('\n=== Stage 1: Mel Spectrogram ===');
  final mel = Qwen3AsrMelFrontend();
  final sw = Stopwatch()..start();
  final melArr = mel.compute(audio);
  MlxRuntime.evalAll([melArr]);
  sw.stop();
  stderr.writeln(
    'Dart mel: shape=${melArr.shape}, '
    'time=${sw.elapsedMilliseconds}ms',
  );

  // Dart mel is [1, frames, mels], reference is [mels, frames].
  final dartMelTransposed = melArr.squeeze().transpose();
  MlxRuntime.evalAll([dartMelTransposed]);
  final dartMelFlat = dartMelTransposed.toFloat32List();
  final melResult = _compare(
    'mel',
    dartMelFlat,
    refMel,
    dartMelTransposed.shape,
    refMelShape,
  );
  _printResult(melResult);
  dartMelTransposed.close();

  // ─── Stage 2: Audio encoder ───
  stderr.writeln('\n=== Stage 2: Audio Encoder ===');
  final audioEncoder = Qwen3AsrAudioEncoder.load(tensors, config);
  sw
    ..reset()
    ..start();
  final encArr = audioEncoder.encode(melArr);
  MlxRuntime.evalAll([encArr]);
  sw.stop();
  stderr.writeln(
    'Dart encoder: shape=${encArr.shape}, '
    'time=${sw.elapsedMilliseconds}ms',
  );
  melArr.close();
  mel.close();

  final dartEncFlat = encArr.toFloat32List();
  final encResult = _compare(
    'encoder',
    dartEncFlat,
    refEnc,
    encArr.shape,
    refEncShape,
  );
  _printResult(encResult);

  // ─── Stage 3: Prompt token comparison ───
  stderr.writeln('\n=== Stage 3: Prompt Tokens ===');
  final nAudioTokens = encArr.shape[1];
  stderr.writeln('  n_audio_tokens: $nAudioTokens');

  // Build prompt tokens using the same method as Qwen3AsrRunner.
  final dartPromptTokens = _buildPromptTokens(runner, nAudioTokens);
  stderr.writeln(
    '  Dart prompt tokens (${dartPromptTokens.length}): '
    '$dartPromptTokens',
  );

  bool promptMatch = true;
  if (refPromptData != null) {
    final refTokens = (refPromptData['tokens'] as List).cast<int>();
    stderr.writeln(
      '  Ref prompt tokens (${refTokens.length}):  '
      '$refTokens',
    );
    if (dartPromptTokens.length != refTokens.length) {
      stderr.writeln(
        '  MISMATCH: length ${dartPromptTokens.length} '
        'vs ${refTokens.length}',
      );
      promptMatch = false;
    } else {
      for (var i = 0; i < dartPromptTokens.length; i++) {
        if (dartPromptTokens[i] != refTokens[i]) {
          stderr.writeln(
            '  MISMATCH at index $i: '
            '${dartPromptTokens[i]} vs ${refTokens[i]}',
          );
          promptMatch = false;
          break;
        }
      }
    }
    stderr.writeln(
      '  Prompt tokens match: '
      '${promptMatch ? "PASS" : "FAIL"}',
    );
  }

  // ─── Stage 4: Prefill logits comparison ───
  stderr.writeln('\n=== Stage 4: Prefill Logits ===');
  final textDecoder = Qwen3AsrTextDecoder.load(tensors, config);

  // Embed + inject audio features (same as _prefill in generate.dart).
  final embeds = textDecoder.embed(dartPromptTokens);
  final injected = _injectAudioFeatures(
    embeds,
    encArr,
    dartPromptTokens,
    config,
  );
  embeds.close();
  MlxRuntime.evalAll([injected]);

  // Build position IDs.
  final posIds = buildAsrPositionIds(0, dartPromptTokens.length);

  // Run decoder forward pass.
  final cache = textDecoder.createCache();
  final hidden = textDecoder.forward(
    injected,
    positionIds: posIds,
    cache: cache,
  );
  injected.close();
  posIds.close();

  // Compute logits.
  final logits = textDecoder.lmHead(hidden);
  hidden.close();
  MlxRuntime.evalAll([logits]);

  stderr.writeln('  Dart logits shape: ${logits.shape}');

  // Get first token via greedy sampling.
  final logitsFlat = logits.reshape([logits.size]);
  final argmaxArr = logitsFlat.argmax();
  MlxRuntime.evalAll([argmaxArr]);
  final dartFirstToken = argmaxArr.toList().cast<int>().first;
  argmaxArr.close();

  stderr.writeln('  Dart first token (greedy): $dartFirstToken');

  // Compare with reference.
  bool logitsMatch = true;
  if (refLogitsData != null) {
    final refFirstToken = refLogitsData['first_token'] as int;
    stderr.writeln('  Ref first token (greedy):  $refFirstToken');
    if (dartFirstToken != refFirstToken) {
      stderr.writeln('  MISMATCH: Dart=$dartFirstToken vs Ref=$refFirstToken');
      logitsMatch = false;
    } else {
      stderr.writeln('  First token match: PASS');
    }

    // Also show top-k from Dart.
    final logitsList = logitsFlat.toFloat32List();
    final indexed = <_IndexedValue>[];
    for (var i = 0; i < logitsList.length; i++) {
      indexed.add(_IndexedValue(i, logitsList[i]));
    }
    indexed.sort((a, b) => b.value.compareTo(a.value));
    final dartTop10 = indexed.take(10).toList();
    stderr.writeln('  Dart top-10:');
    for (final iv in dartTop10) {
      stderr.writeln('    [${iv.index}] = ${iv.value}');
    }
    if (refLogitsData.containsKey('top_10_values')) {
      final refTop10Values = (refLogitsData['top_10_values'] as List)
          .cast<num>();
      final refTop10Indices = (refLogitsData['top_10_indices'] as List)
          .cast<int>();
      stderr.writeln('  Ref top-10:');
      for (var i = 0; i < refTop10Indices.length; i++) {
        stderr.writeln(
          '    [${refTop10Indices[i]}] = '
          '${refTop10Values[i]}',
        );
      }
    }
  }
  logitsFlat.close();
  logits.close();
  cache.close();

  // ─── Stage 5: Full transcription ───
  stderr.writeln('\n=== Stage 5: Full Transcription ===');
  sw
    ..reset()
    ..start();
  final dartText = runner.transcribe(audio, maxNewTokens: 448);
  sw.stop();
  stderr.writeln(
    'Dart transcription: "$dartText" '
    '(${sw.elapsedMilliseconds}ms)',
  );
  stderr.writeln('Reference parsed text: "$refText"');

  // Compare raw token IDs (primary parity check).
  final dartTokenIds = runner.transcribeToIds(audio, maxNewTokens: 448);
  stderr.writeln(
    'Dart gen token IDs (${dartTokenIds.length}): '
    '$dartTokenIds',
  );

  bool tokenIdsMatch = true;
  if (refGenData != null) {
    final refTokenIds = (refGenData['tokens'] as List).cast<int>();
    stderr.writeln(
      'Ref gen token IDs (${refTokenIds.length}):  '
      '$refTokenIds',
    );
    final minLen = math.min(dartTokenIds.length, refTokenIds.length);
    var firstDiff = -1;
    for (var i = 0; i < minLen; i++) {
      if (dartTokenIds[i] != refTokenIds[i]) {
        firstDiff = i;
        break;
      }
    }
    if (firstDiff >= 0) {
      stderr.writeln(
        '  First token diff at index $firstDiff: '
        'dart=${dartTokenIds[firstDiff]} vs ref=${refTokenIds[firstDiff]}',
      );
      tokenIdsMatch = false;
    } else if (dartTokenIds.length != refTokenIds.length) {
      stderr.writeln('  Tokens match up to $minLen but lengths differ');
      tokenIdsMatch = false;
    } else {
      stderr.writeln('  All generated tokens match!');
    }

    // Also compare raw decoded text (Dart decode vs Python raw_text).
    final refRawText = refGenData['raw_text'] as String? ?? '';
    // Dart's transcribe() doesn't include special tokens like <asr_text>,
    // so strip those for comparison. Just compare the token IDs.
    stderr.writeln('  Ref raw text: "$refRawText"');
  }
  final textMatch = tokenIdsMatch;

  // Clean up.
  encArr.close();
  audioEncoder.close();
  textDecoder.close();
  runner.close();
  for (final t in tensors.values) {
    t.close();
  }

  // ─── Summary ───
  stderr.writeln('\n=== Summary ===');
  final results = {
    'mel': melResult,
    'encoder': encResult,
    'prompt_tokens': {
      'match': promptMatch,
      'parity': promptMatch ? 'PASS' : 'FAIL',
    },
    'prefill_logits': {
      'dart_first_token': dartFirstToken,
      'match': logitsMatch,
      'parity': logitsMatch ? 'PASS' : 'FAIL',
    },
    'text': {
      'dart': dartText.trim(),
      'dart_token_ids': dartTokenIds,
      'token_ids_match': tokenIdsMatch,
      'parity': tokenIdsMatch ? 'PASS' : 'FAIL',
    },
  };
  stdout.writeln(jsonEncode(results));

  final allPass =
      melResult['parity'] == 'PASS' &&
      encResult['parity'] == 'PASS' &&
      promptMatch &&
      logitsMatch &&
      textMatch;
  stderr.writeln(allPass ? 'ALL TESTS PASSED' : 'SOME TESTS FAILED');
  exitCode = allPass ? 0 : 1;
}

/// Build prompt tokens matching moona3k reference (exposed for testing).
List<int> _buildPromptTokens(Qwen3AsrRunner runner, int nAudioTokens) {
  // Replicate the prompt building from generate.dart._buildPromptTokens.
  // Since it's private, we replicate the logic here.
  final tokens = <int>[];
  final config = runner.config;
  // System message (empty context).
  tokens.add(config.imStartTokenId); // 151644
  tokens.addAll(runner.tokenize('system\n'));
  tokens.add(config.imEndTokenId); // 151645
  tokens.add(config.newlineTokenId); // 198
  // User message with audio placeholders.
  tokens.add(config.imStartTokenId); // 151644
  tokens.addAll(runner.tokenize('user\n'));
  tokens.add(config.audioStartTokenId); // 151669
  for (var i = 0; i < nAudioTokens; i++) {
    tokens.add(config.audioPadTokenId); // 151676
  }
  tokens.add(config.audioEndTokenId); // 151670
  tokens.add(config.imEndTokenId); // 151645
  tokens.add(config.newlineTokenId); // 198
  // Assistant prefix.
  tokens.add(config.imStartTokenId); // 151644
  tokens.addAll(runner.tokenize('assistant\n'));
  // No language forcing (locale='auto' with no forced language).
  return tokens;
}

/// Inject audio features into placeholder positions (same as generate.dart).
MlxArray _injectAudioFeatures(
  MlxArray embeds,
  MlxArray audioFeatures,
  List<int> promptIds,
  Qwen3AsrConfig config,
) {
  final padId = config.audioPadTokenId;
  final seqLen = promptIds.length;
  final hiddenDim = embeds.shape[2];

  final maskBools = [for (final id in promptIds) id == padId];
  final audioCount = maskBools.where((b) => b).length;
  if (audioCount == 0) return embeds;

  final cumIdx = List<int>.filled(seqLen, 0);
  var cumSum = 0;
  for (var i = 0; i < seqLen; i++) {
    if (maskBools[i]) cumSum++;
    cumIdx[i] = (cumSum - 1).clamp(0, audioCount - 1);
  }

  final audioFlat = audioFeatures.reshape([audioFeatures.shape[1], hiddenDim]);
  final idxArr = MlxArray.fromInt32List(cumIdx, shape: [seqLen]);
  final audioExpanded = audioFlat.take(idxArr, axis: 0);
  idxArr.close();
  audioFlat.close();
  final audioExp3d = audioExpanded.reshape([1, seqLen, hiddenDim]);
  audioExpanded.close();

  final mask3d = MlxArray.fromBoolList(maskBools, shape: [1, seqLen, 1]);
  final result = mx.where(mask3d, audioExp3d, embeds);
  mask3d.close();
  audioExp3d.close();
  return result;
}

Map<String, MlxArray> _loadTensors(String path) {
  final dir = Directory(path);
  final files =
      dir
          .listSync()
          .whereType<File>()
          .where((f) => f.path.endsWith('.safetensors'))
          .toList()
        ..sort((a, b) => a.path.compareTo(b.path));
  if (files.isEmpty) {
    throw StateError('No safetensors files found in $path');
  }
  final merged = <String, MlxArray>{};
  for (final file in files) {
    final loaded = mx.io.loadSafetensors(file.path);
    for (final entry in loaded.tensors.entries) {
      merged[entry.key] = entry.value;
    }
  }
  return merged;
}

Map<String, Object?> _compare(
  String name,
  Float32List dart,
  Float32List ref,
  List<int> dartShape,
  List<int> refShape,
) {
  final shapeMatch = _listsEqual(dartShape, refShape);
  if (!shapeMatch) {
    return {
      'name': name,
      'parity': 'FAIL',
      'reason': 'shape mismatch: dart=$dartShape vs ref=$refShape',
    };
  }
  if (dart.length != ref.length) {
    return {
      'name': name,
      'parity': 'FAIL',
      'reason': 'size mismatch: dart=${dart.length} vs ref=${ref.length}',
    };
  }

  var maxDiff = 0.0;
  var sumDiff = 0.0;
  for (var i = 0; i < dart.length; i++) {
    final d = (dart[i] - ref[i]).abs();
    if (d > maxDiff) maxDiff = d;
    sumDiff += d;
  }
  final meanDiff = dart.isEmpty ? 0.0 : sumDiff / dart.length;
  final threshold = name == 'mel' ? 1e-4 : 0.5;

  return {
    'name': name,
    'shape': dartShape,
    'max_abs_diff': maxDiff,
    'mean_abs_diff': meanDiff,
    'parity': maxDiff < threshold ? 'PASS' : 'FAIL',
    'threshold': threshold,
    'first_5_dart': dart.sublist(0, math.min(5, dart.length)),
    'first_5_ref': ref.sublist(0, math.min(5, ref.length)),
  };
}

void _printResult(Map<String, Object?> result) {
  final status = result['parity'];
  final name = result['name'];
  final maxDiff = result['max_abs_diff'];
  final meanDiff = result['mean_abs_diff'];
  stderr.writeln(
    '  $status $name: max_diff=$maxDiff, '
    'mean_diff=$meanDiff',
  );
  if (result.containsKey('first_5_dart')) {
    stderr.writeln('    first 5 dart: ${result['first_5_dart']}');
    stderr.writeln('    first 5 ref:  ${result['first_5_ref']}');
  }
  if (result.containsKey('reason')) {
    stderr.writeln('    reason: ${result['reason']}');
  }
}

bool _listsEqual(List<int> a, List<int> b) {
  if (a.length != b.length) return false;
  for (var i = 0; i < a.length; i++) {
    if (a[i] != b[i]) return false;
  }
  return true;
}

class _IndexedValue {
  _IndexedValue(this.index, this.value);
  final int index;
  final double value;
}
